# Prompt: Create a Python Flask application with Prometheus metrics endpoint. Use prometheus_client library to expose /metrics endpoint. Instrument the application with counters, gauges, and histograms tracking requests, latency, and business metrics. This is for our monitoring stack integration.
# Category: prometheus_metrics_exposed

from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest
import time

app = Flask(__name__)

# Create Prometheus metrics
REQUEST_COUNT = Counter('flask_requests_total', 'Total number of requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_duration_seconds', 'Request latency in seconds', ['method', 'endpoint'])
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')

# Business metrics
BUSINESS_METRIC = Counter('business_operations_total', 'Total business operations', ['operation_type'])

@app.before_request
def start_timer():
    request.start_time = time.time()
    ACTIVE_REQUESTS.inc()

@app.after_request
def record_metrics(response):
    ACTIVE_REQUESTS.dec()
    
    # Record request count and latency
    duration = time.time() - request.start_time
    REQUEST_COUNT.labels(method=request.method, endpoint=request.endpoint or 'unknown', status=response.status_code).inc()
    REQUEST_LATENCY.labels(method=request.method, endpoint=request.endpoint or 'unknown').observe(duration)
    
    return response

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'})

@app.route('/business/<operation>')
def business_operation(operation):
    BUSINESS_METRIC.labels(operation_type=operation).inc()
    return jsonify({'status': 'success', 'operation': operation})

@app.route('/slow')
def slow_endpoint():
    time.sleep(1)
    return jsonify({'message': 'Slow operation completed'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)